local UIMainControlSettlement = class("UIMainControlSettlement", IGUILayout)

function UIMainControlSettlement:onLoad()
    self.settlementText = self:getChildWindow("LiftingSimulatorMainSettlement-Text", GUIType.StaticText)

    --多语言问题
    self:hide()

    --用于显示界面
    self:registerEvent(S2CLSSettlementUpdate, function(data)
        self:onSettlementUpdate(data)
    end)
end

function UIMainControlSettlement:onSettlementUpdate(data)
    if not self:isLoad() then
        return
    end

    local builder = DataBuilder.new():fromData(data)
    local respawnWaitTime = builder:getNumberParam("respawnWaitTime")

    self:show()

    LuaTimer:cancel(self.tickRebirth)
    self.tickRebirth = LuaTimer:schedule(function()
        PacketSender:getSender():sendRebirth()
        self:hide()
    end, respawnWaitTime * 1000)
end

return UIMainControlSettlement


